import React, { useState, useEffect } from 'react';

function App() {
  const [view, setView] = useState('home');
  // Estado para guardar a lista de campeonatos vindos do banco de dados
  const [campeonatos, setCampeonatos] = useState([]);

  // Função para buscar os campeonatos no Backend
  const carregarCampeonatos = async () => {
    try {
      const resposta = await fetch('http://localhost:5000/championships');
      const dados = await resposta.json();
      setCampeonatos(dados);
    } catch (erro) {
      console.error("Erro ao carregar do banco:", erro);
    }
  };

  // useEffect faz a busca rodar assim que o site abre
  useEffect(() => {
    carregarCampeonatos();
  }, []);

  // Função para criar um campeonato novo (Integrando com o Banco)
  const criarCampeonatoTeste = async () => {
    const novoCampeonato = {
      nome: "Liga dos Campeões eFootball " + Math.floor(Math.random() * 100),
      formato: "pontos-corridos",
      qtd_times: 20
    };

    try {
      await fetch('http://localhost:5000/championships', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(novoCampeonato)
      });
      // Recarrega a lista para mostrar o que acabou de ser criado!
      carregarCampeonatos();
    } catch (erro) {
      console.error("Erro ao criar:", erro);
    }
  };

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans">
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card">
        <h1 className="text-2xl font-bold italic text-ef-green">eFOOTBALL CHAMP</h1>
        <div className="space-x-6">
          <button onClick={() => setView('home')} className="hover:text-ef-green">Campeonatos</button>
          <button className="bg-ef-green text-black px-4 py-2 rounded-full font-bold">Entrar</button>
        </div>
      </nav>

      <main className="p-8">
        <header className="mb-10">
          <h2 className="text-4xl font-extrabold">Gerencie seus Torneios Profissionais</h2>
          <p className="text-gray-400 mt-2">Crie tabelas, organize times e acompanhe resultados em tempo real.</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          
          {/* Mapeando os campeonatos que vieram do banco de dados! */}
          {campeonatos.map((champ) => (
            <div key={champ._id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition-all cursor-pointer">
              <div className="bg-ef-green text-black text-xs font-bold px-2 py-1 rounded inline-block mb-4">OPEN</div>
              <h3 className="text-xl font-bold mb-2">{champ.nome}</h3>
              <p className="text-gray-400 text-sm">{champ.qtd_times} Times • {champ.formato.replace('-', ' ')}</p>
              <button className="mt-6 w-full py-2 border border-ef-green text-ef-green rounded-lg hover:bg-ef-green hover:text-black transition">Ver Tabela</button>
            </div>
          ))}
          
          {/* Botão para criar campeonato no banco */}
          <div 
            onClick={criarCampeonatoTeste}
            className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex flex-col items-center justify-center text-gray-500 hover:text-ef-green hover:border-ef-green transition cursor-pointer"
          >
             <span className="text-4xl mb-2">+</span>
             <p className="font-bold">Criar Campeonato</p>
             <p className="text-xs text-center mt-2">(Clique para gerar e salvar no banco)</p>
          </div>

        </div>
      </main>
    </div>
  );
}

export default App;
